class Solution {
    public long validSubstringCount(String word1, String word2) {
        int m = word1.length(), n = word2.length();
        int[] count = new int[26];
        int match = 0;
        long res = 0;

        for (int i = 0; i < m; i++) {
            if (i >= n) {
                count[word1.charAt(i - n) - 'a']--;
                if (word1.charAt(i - n) == word2.charAt(0)) match--;
            }

            count[word1.charAt(i) - 'a']++;
            if (word1.charAt(i) == word2.charAt(0)) match++;

            if (i >= n - 1) {
                if (match == n) {
                    res++;
                }
            } else {
                int mismatch = 0;
                int[] tempCount = new int[26];
                for (int j = 0; j < i + 1; j++) {
                    if (count[word1.charAt(j) - 'a'] > 1 || (word1.charAt(j) != word2.charAt(0) && tempCount[word1.charAt(j) - 'a'] == 0)) {
                        mismatch++;
                        tempCount[word1.charAt(j) - 'a']++;
                    }
                }
                if (mismatch == n) res++;
            }
        }
        return res;
    }
}
